}
private int dfs(TreeNode n, long curr, int target, Map<Long, Integer> map) {
    if (n == null) return 0;
    curr += n.val;
    int count = map.getOrDefault(curr - target, 0);
    map.put(curr, map.getOrDefault(curr, 0) + 1);
    count += dfs(n.left, curr, target, map) + dfs(n.right, curr, target, map);
    map.put(curr, map.get(curr) - 1);
    return count;
}

