public class Stack {
    private int[] arr;
    private int top;
    private int capacity;

    public Stack(int size) {
        arr = new int[size];
        capacity = size;
        top = -1;
    }

    public void push(int x) {
        if (top == capacity - 1) return; // Stack overflow
        arr[++top] = x;
    }

    public int pop() {
        if (top == -1) return -1; // Stack underflow
        return arr[top--];
    }
}

