def canPartitionKSubsets(nums, k):
    total = sum(nums)
    if total % k != 0: return False
    target = total // k
    memo = {}
    def backtrack(mask, curr_sum):
        if mask == (1 << len(nums)) - 1: return True
        if mask in memo: return memo[mask]
        for i in range(len(nums)):
            if not (mask & (1 << i)) and curr_sum + nums[i] <= target:
                if backtrack(mask | (1 << i), (curr_sum + nums[i]) % target):
                    memo[mask] = True
                    return True
        memo[mask] = False
        return False
    return backtrack(0, 0)

int longestIncreasingPath(std::vector<std::vector<int>>& matrix) {
    int R = matrix.size(), C = matrix[0].size(), res = 0;
    std::vector<std::vector<int>> dp(R, std::vector<int>(C, 0));
    auto dfs = [&](auto self, int r, int c) -> int {
        if (dp[r][c]) return dp[r][c];
        int dr[] = {0, 0, 1, -1}, dc[] = {1, -1, 0, 0}, maxLen = 1;
        for (int i = 0; i < 4; i++) {
            int nr = r + dr[i], nc = c + dc[i];
            if (nr >= 0 && nr < R && nc >= 0 && nc < C && matrix[nr][nc] > matrix[r][c])
                maxLen = std::max(maxLen, 1 + self(self, nr, nc));
        }
        return dp[r][c] = maxLen;
    };
    for (int i = 0; i < R; i++) for (int j = 0; j < C; j++) res = std::max(res, dfs(dfs, i, j));
    return res;
}

