    return count;
}
private void solve(int row, int cols, int d1, int d2, int n) {
    if (row == n) { count++; return; }
    int available = ((1 << n) - 1) & (~(cols | d1 | d2));
    while (available != 0) {
        int pos = available & (-available);
        available &= ~pos;
        solve(row + 1, cols | pos, (d1 | pos) << 1, (d2 | pos) >> 1, n);
    }
}

