    Map<Integer, Integer> dp = new HashMap<>();
    for (int k = 0; k < n; k++) {
        for (int j = 0; j < k; j++) {
            int i = index.getOrDefault(arr[k] - arr[j], -1);
            if (i >= 0 && i < j) {
                int len = dp.getOrDefault(i * n + j, 2) + 1;
                dp.put(j * n + k, len);
                maxLen = Math.max(maxLen, len);
